```ts
import fs from "node:fs/promises";
import path from "node:path";
import OpenAI from "openai";

const client = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

type Msg =
  | { role: "system" | "user"; content: string }
  | { role: "assistant"; content: string | null; tool_calls?: any[] }
  | { role: "tool"; tool_call_id: string; content: string };

const tools = [
  {
    type: "function",
    function: {
      name: "read_file",
      description: "Read text file from current workspace",
      parameters: {
        type: "object",
        properties: {
          file_path: { type: "string" }
        },
        required: ["file_path"]
      }
    }
  }
] as const;

async function readFileTool(filePath: string): Promise<string> {
  const abs = path.resolve(process.cwd(), filePath);
  const content = await fs.readFile(abs, "utf-8");
  return content.slice(0, 4000);
}

async function main() {
  const messages: Msg[] = [
    { role: "system", content: "You are a coding assistant. Use tools when needed." },
    { role: "user", content: "读取 package.json 并告诉我 name 是什么" }
  ];

  for (let i = 0; i < 5; i++) {
    const res = await client.chat.completions.create({
      model: "gpt-4o-mini",
      messages: messages as any,
      tools: tools as any,
      tool_choice: "auto"
    });

    const msg = res.choices[0]?.message;
    if (!msg) throw new Error("No assistant message");
    messages.push({
      role: "assistant",
      content: msg.content ?? null,
      tool_calls: msg.tool_calls
    });

    const calls = msg.tool_calls ?? [];
    if (calls.length === 0) {
      console.log("\nAssistant:", msg.content);
      break;
    }

    for (const call of calls) {
      if (call.function.name !== "read_file") continue;
      const args = JSON.parse(call.function.arguments || "{}");
      const output = await readFileTool(args.file_path);
      messages.push({
        role: "tool",
        tool_call_id: call.id,
        content: output
      });
    }
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
```

5. 运行
```bash
node -e "console.log('name check')"
pnpm tsx src/main.ts
```

